import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Dashboards Overview (New)","description":"","frontmatter":{"title":"Dashboards Overview (New)","slug":"analysis-dashboards-overview-new"},"headers":[],"relativePath":"marketer-hub/analysis-dashboards-overview-new.md","filePath":"marketer-hub/analysis-dashboards-overview-new.md"}'),i={name:"marketer-hub/analysis-dashboards-overview-new.md"};function s(n,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p><a href="https://branchdocs.app.link/e/dashboards-overview-to-all-dashboards" target="_blank" rel="noreferrer">Analysis Dashboards</a> offer a powerful, sophisticated analytics experience.</p><p>Using Ivy, your strategic AI partner in Branch, you can <strong>build dashboards with plain English prompts and get answers to everyday business questions</strong> that come up in your marketing workflows.</p><p>A dashboard is an individual page that contains a specific set of widgets, which themselves display metrics or charts. Use each dashboard to tell a different story with your Branch data and to track your company&#39;s marketing growth from different angles.</p><p>By drilling down into specific campaigns, you can break out your data by platform, channel, and more to see what&#39;s really driving results. This visibility empowers you to effectively <strong>optimize your ad spend</strong> across all your active campaigns.</p><p>Share the data in your dashboards in multiple ways to <strong>report important campaign metrics</strong> to internal stakeholders, and stay informed about your campaign performance and notable changes in your data with <strong>KPI alerts</strong> delivered to your email.</p><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this feature yet?</p><p>Analysis is the next evolution in Branch&#39;s marketing analytics and reporting functionality, bringing together data from ads, social media, SEO, email, and more in one cohesive experience.</p><p>Analysis is being rolled out to customers in phases. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p><p>In the meantime, please continue to refer to our <a href="./dashboard-exports-index.html">legacy documentation for reporting</a>.</p></div><h3 id="key-terms" tabindex="-1">Key terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key terms&quot;">​</a></h3><p>The following terms are used extensively throughout this guide. Please take note of their definitions.</p><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td>Widget</td><td>A single metric or chart that displays an aspect of your Branch data. You can edit widgets extensively to make sure they capture the data you&#39;re looking for. If you&#39;d like to understand where an aggregated widget metric is coming from, you can preview the underlying data from the widget directly (up to 1,000 rows). You can also download data from individual widgets.</td></tr><tr><td>Dashboard</td><td>A collection of widgets that live on a single page. Dashboards can be exported as a single entity, and you can share an entire dashboard in presentation mode. A core list of your individual dashboards are listed prominently under <strong>Analysis</strong> in the left-side navigation in Branch. To see the rest of your dashboards, select <a href="https://branchdocs.app.link/e/dashboards-overview-to-all-dashboards" target="_blank" rel="noreferrer"><strong>All Dashboards</strong></a>.</td></tr><tr><td>Data Source</td><td>Branch supports different data sources to power your dashboards. Each data source makes different dimensions of your data available. Depending on what data you want to display, you can use one or all of these data sources in a single dashboard or widget. The supported data sources are: - <strong>Activity</strong>: Default data source for most reporting. Provides extensive tracking of most user behavior. - <strong>Activity Extended</strong>: A more comprehensive version of Activity that includes a wider range of fields and dimensions. - <strong>SKAdNetwork</strong>: Contains SKAN data exclusively. - <strong>Unified Activity and SKAdNetwork</strong>: Combines Activity and SKAdNetwork data to provide a unified view of campaign performance. - <strong>Fraud</strong>: Track fraud detection and prevention performance across campaigns and ad partners. - <strong>Cohorts</strong>: Track user behavior over time by grouping users based on acquisition dates. - <strong>Funnel</strong>: Multi-touch attribution paths showing touchpoints users interact with before converting. - <strong>Link Analytics</strong>: Link-level performance reporting with link-specific dimensions. Learn more about each data source and its available fields in <a href="./analysis-data-sources-new.html">Analysis Data Sources Reference</a>.</td></tr><tr><td>Ivy</td><td>The sophisticated, AI-powered partner that helps you uncover and grow your analytics story. Ivy provides you with intelligent insights into your data, and answers your natural language questions in real time. You can talk to Ivy using the <strong>Ask Ivy</strong> prompt at the top of each dashboard, or you can select the <strong>Ivy</strong> button on a widget to ask it deeper questions about that specific widget&#39;s data.</td></tr><tr><td>Prompt</td><td>An individual query or instruction you give Ivy so it can start processing your requests and answering your questions. A <a href="./analysis-dashboards.html#craft-prompts-for-ivy">well-crafted prompt</a> helps Ivy give you a relevant answer that meets your criteria.</td></tr></tbody></table><h3 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h3><p>The following Analysis Dashboards functionality is available depending on your Branch plan:</p><ul><li>Creating and editing dashboards</li><li>AI prompt widget at dashboard-level</li><li>AI on individual widgets within dashboards</li></ul><p>Please note that <strong>some plans do not include the ability to create or edit dashboards</strong>; in these cases, you will only be able to view Branch&#39;s <a href="./analysis-dashboards.html#default-dashboards">default set of dashboards</a>.</p><p>For more information, please visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page or <a href="https://branchdocs.app.link/e/analysis-sales" target="_blank" rel="noreferrer">contact our Sales team</a>.</p><h2 id="dashboards" tabindex="-1">Dashboards <a class="header-anchor" href="#dashboards" aria-label="Permalink to &quot;Dashboards&quot;">​</a></h2><p>Analysis Dashboards are both powerful and intuitive, so you can glean deep insights from them without extensive guidance. However, it is helpful to understand the basic functionality before you dive into intermediate and advanced queries.</p><p>This section will get you started using dashboards quickly, and will use common marketing concepts to inform the types of questions used to prompt Ivy.</p><h4 id="default-dashboards" tabindex="-1">Default dashboards <a class="header-anchor" href="#default-dashboards" aria-label="Permalink to &quot;Default dashboards&quot;">​</a></h4><p>Once you have access to Analysis Dashboards and you log in to your Branch account, you&#39;ll notice certain pre-configured dashboards are already available and ready for you to use immediately.</p><p>Part of this set is an important dashboard called <a href="https://branchdocs.app.link/e/analysis-dashboards-channel-performance" target="_blank" rel="noreferrer"><strong>Channel Performance</strong></a>, which you will see listed directly under the <strong>Analysis</strong> section in the left-side navigation of Branch.</p><p>The other part of this set is our <strong>classic suite of dashboards</strong>. These dashboards are meant to replace our legacy data reporting pages, and are useful jumping off points for anyone getting started.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Please note that there is <strong>not a 1:1 relationship between legacy data reporting pages and the new classic suite</strong> of dashboards. However, we have tried to maintain parity where possible.</p><p>Also, the default dashboards you see depends on your Branch package.</p></div><table tabindex="0"><thead><tr><th>Dashboard name</th><th>Legacy equivalent</th><th>Description</th></tr></thead><tbody><tr><td>Channel Performance</td><td>NA</td><td>Track marketing channel performance using key acquisition and engagement metrics including installs, opens, clicks, and impressions broken out by paid and organic channels. Quickly assess channel effectiveness and optimize marketing spend by comparing performance across different acquisition sources.</td></tr><tr><td>Classic Suite - Summary</td><td>Overview → Summary</td><td>Track performance across paid and organic channels, displaying key metrics like clicks, impressions, installs, and opens alongside overall monthly install trends. It includes a breakdown by ad partner to help evaluate which advertising partnerships are driving the most value.</td></tr><tr><td>Classic Suite - Sources</td><td>Overview → Sources</td><td>Track unique user actions per campaign and includes a trend analysis of unique user engagement to help identify campaign quality over time.</td></tr><tr><td>Classic Suite - Ads Unified</td><td>Ads Analytics → Unified</td><td>Track SKAdNetwork (SKAN) and non-SKAN attribution data to show which campaigns are actually driving installs, purchases, and revenue. See the full picture of campaign performance by tracking both total activity and unique users across different measurement methods.</td></tr><tr><td>Classic Suite - Ads Activity</td><td>Ads Analytics → Activity</td><td>Track paid advertising performance across platforms and campaigns, showing both total and unique user actions, from clicks to purchases. See a trend line of external clicks by platform over time, which demonstrates platform performance patterns and helps you optimize your ad spending.</td></tr><tr><td>Classic Suite - SKAdNetwork</td><td>Ads Analytics → SKAdNetwork</td><td>Track detailed SKAN attribution data, showing install trends over time, along with breakdowns by ad network, campaign, and source app. Understand iOS install performance and optimize SKAN-based campaign strategies across different ad partners.</td></tr><tr><td>Classic Suite - SEO Analytics</td><td>SEO → Analytics</td><td>Track organic search performance by channel, showing installs, opens, and purchases from SEO traffic. See a trend line of opens over time to monitor organic search engagement and identify which channels are driving the most valuable organic users.</td></tr><tr><td>Classic Suite - Journeys Activity</td><td>Journeys → Activity</td><td>Track Journeys advertising campaign performance across platforms, showing external click trends over time and detailed attribution metrics including installs, opens, purchases, and revenue. Monitor Journeys campaign effectiveness and optimize platform spending based on conversion performance.</td></tr><tr><td>Classic Suite - Email Activity</td><td>Email → Activity</td><td>Track Branch Email marketing performance across platforms and campaigns, showing external click trends over time plus detailed attribution metrics for both total and unique user actions. Measure email campaign effectiveness, from clicks to purchases and revenue generation.</td></tr><tr><td>Classic Suite - Short Links</td><td>NA</td><td>Track Short Link analytics performance across campaigns and channels, showing click-to-open rates, installs, and conversion metrics with detailed breakdowns by operating system, features, and top-performing campaigns. Monitor link effectiveness over time, optimize channel strategies based on weekly performance trends, and identify high-converting links for improved engagement outcomes.</td></tr><tr><td>Fraud</td><td>Fraud → Activity</td><td>Track fraud detection and prevention performance across campaigns and ad partners. See <a href="./custom-exports-api.html#available-topics">blocked events</a> and monitor the impact of your fraud protection rules to optimize ad spend quality.</td></tr><tr><td>Cohorts</td><td>Ads Analytics → Cohorts (Acquisition only)</td><td>Track user behavior over time by grouping users based on app install acquisition dates. Analyze retention, lifetime value, and campaign ROI to understand long-term user performance and guide future investment decisions. <strong>Note</strong>: Re-engagement cohort data is not yet available in Analysis.</td></tr><tr><td>Funnel</td><td>NA</td><td>Track multi-touch attribution paths showing up to three touchpoints users interact with before converting. Identify assisted touches and understand which campaigns work together to drive conversions.</td></tr></tbody></table><h3 id="view-dashboards" tabindex="-1">View dashboards <a class="header-anchor" href="#view-dashboards" aria-label="Permalink to &quot;View dashboards&quot;">​</a></h3><p>Under the <strong>Analysis</strong> section in the left-side navigation in Branch, you will see several of your core dashboards listed by name. Select any of these dashboards to view them.</p><p>To view a dashboard <em>not</em> featured in that list, select <a href="https://branchdocs.app.link/e/analysis-dashboards-all-dashboards" target="_blank" rel="noreferrer"><strong>All Dashboards</strong></a>and select the dashboard you&#39;re looking for from the full list.</p><p>From this page, you can also favorite a dashboard by selecting the <strong>star icon</strong> next to its name. You can then filter the full list by dashboards that are starred or not starred.</p><p>Dashboards that have the <strong>verified checkmark icon</strong> next to their names are dashboards that have been created for you by Branch. You can filter by verified or non-verified dashboards.</p><p>To view only the dashboards that you&#39;ve created, you can also select the tab that says <strong>Yours</strong> at the top of the page.</p><h3 id="create-a-dashboard" tabindex="-1">Create a dashboard <a class="header-anchor" href="#create-a-dashboard" aria-label="Permalink to &quot;Create a dashboard&quot;">​</a></h3><p>To create a new Analysis Dashboard:</p><ol><li>Select <strong>Analysis</strong> in the left-side navigation in Branch, then select <strong>All Dashboards</strong>.</li><li>Select the <strong>Create Dashboard</strong> button in the top-right corner of the page.</li><li>Give the dashboard a unique name in the <strong>Name</strong> field.</li><li>Give the dashboard a description in the <strong>Description</strong> field that explains the purpose of the dashboard and how others should read it.</li><li>Select the <strong>Create</strong> button.</li></ol><p>You are now ready to <a href="./analysis-dashboards.html#create-and-configure-widget">add widgets</a> to your new dashboard.</p><h3 id="copy-a-dashboard" tabindex="-1">Copy a dashboard <a class="header-anchor" href="#copy-a-dashboard" aria-label="Permalink to &quot;Copy a dashboard&quot;">​</a></h3><p>Sometimes you may want to use a certain dashboard as a starting point for creating your own version with different metrics. To do this, start by copying the original dashboard.</p><p>To make a copy of a dashboard:</p><ol><li>Navigate to the dashboard you&#39;re interested in copying, and select the <strong>three dot icon</strong> in the upper-right corner.</li><li>In the menu that opens, select <strong>Make a copy</strong>.</li><li>Give the dashboard a unique name in the <strong>Name</strong> field.</li><li>Give the dashboard a description in the <strong>Description</strong> field that explains the purpose of the dashboard and how others should read it.</li><li>Select the <strong>Create</strong> button.</li></ol><h3 id="edit-a-dashboard" tabindex="-1">Edit a dashboard <a class="header-anchor" href="#edit-a-dashboard" aria-label="Permalink to &quot;Edit a dashboard&quot;">​</a></h3><p>Dashboards can be edited, as long as they aren&#39;t one of the <a href="./analysis-dashboards.html#default-dashboards">dashboards created by Branch</a>. You will see the author of these dashboards listed as &quot;Branch&quot; and they will have a <strong>verified checkmark icon</strong> next to their names on the <strong>All Dashboards</strong> page.</p><p>Also, please note that if someone else on your team created the dashboard, they will need to give you edit permissions before you can edit their dashboard.</p><p>To edit a dashboard:</p><ol><li><p>Navigate to the dashboard you&#39;re interested in editing, and select the <strong>three dot icon</strong> in the upper-right corner.</p></li><li><p>In the menu that opens, select <strong>Edit</strong>.</p></li><li><p>From here, you can:</p><ol><li><p>Add notes: Select the <strong>Add note</strong> button in the top-right corner to add a widget to the dashboard that holds a note you want to keep. You can move and resize this widget. You can also add multiple notes to a single dashboard.</p></li><li><p>Add filters: Select the <strong>Add filter</strong> button in the top-right corner to add a new filter and get taken to its configuration menu. When you are finished configuring it, select the <strong>Apply</strong> button.</p><ol><li>To learn more about configuring filters, read &quot;<a href="./analysis-dashboards.html#configure-dashboard-filter">Configure dashboard filter</a>.&quot;</li></ol></li><li><p>Edit the dashboard name and description: Select the <strong>pencil icon</strong> next to the name of the dashboard to give it a new name or description. Select <strong>Save</strong> to save your changes.</p></li><li><p>Remove filters: The filters applied to your dashboard are listed at the top in individual bubbles. To remove a filter, select the <strong>X icon</strong> that appears when you hover over it.</p></li><li><p>Edit filters: From the filters listed at the top of the page, select the one you want to edit to see its configuration menu. To learn more about configuring filters, read &quot;<a href="./analysis-dashboards.html#configure-dashboard-filter">Configure dashboard filter</a>.&quot;</p></li><li><p>Move widgets: Hover over the top edge of the widget, until your cursor becomes an <strong>icon</strong> <strong>with</strong> <strong>four arrows</strong> and the <strong>light gray bar</strong> appears. Select the light gray bar and drag the widget into place.</p></li><li><p>Delete widgets: Hover over the widget and select the <strong>three dot icon</strong> that appears. Select <strong>Delete</strong> to delete your widget.</p><ol><li>Warning: Please note that deleting a widget is a <strong>permanent</strong> action and cannot be undone!</li></ol></li><li><p>Resize widgets: There are two ways to resize widgets:</p><ol><li>Hover over the widget and select the <strong>three dot icon</strong> that appears. Select the visual representation of the dimensions you would like the widget to change to from the set of options.</li><li>Hover over the bottom-right corner edge of a widget until your cursor becomes an <strong>arrow icon</strong>. Drag the widget&#39;s corner to make it bigger or smaller.</li></ol></li></ol></li><li><p>When you are done making changes to your dashboard, select the <strong>Save</strong> button.</p><ol><li>If you would like to discard the changes you&#39;ve made, select the <strong>Cancel</strong> button instead. Then select <strong>Discard changes</strong>.</li></ol></li></ol><h3 id="configure-dashboard-filter" tabindex="-1">Configure dashboard filter <a class="header-anchor" href="#configure-dashboard-filter" aria-label="Permalink to &quot;Configure dashboard filter&quot;">​</a></h3><p>Filters help make sure you&#39;re only seeing the data you want to see on your dashboard. To set a filter at the dashboard level:</p><ol><li><p>Navigate to the dashboard you&#39;re interested in creating a filter for and select the <strong>three dot icon</strong> in the upper-right corner.</p></li><li><p>In the menu that opens, select <strong>Edit</strong>.</p></li><li><p>Select the <strong>Add filter</strong> button in the top-right corner.</p></li><li><p>A list of possible filters will open. Select the filter that you would like to add.</p></li><li><p>The filter&#39;s configuration menu will open. This menu has four main sections:</p><ol><li><p>Default values: Set the values you want to either include or exclude from your dashboard for this particular filter. Depending on the type of filter, you may be asked to select values from a list, or add your own conditional statements for what values to filter in or out.</p><ol><li><p>Example: To see only your social media campaigns, selected &quot;Feature&quot; as your filter and only include data where the value is <code>social</code>.</p><ol><li>Please note that by default, selecting values for a filter will limit the values displayed in any future filters you create for this dashboard. In this example, if you tried to add &quot;Branch Channel&quot; as a second filter, you would only be able to select a channel that applies to social media campaigns, like <code>Short Links</code>. To change this, enable the <strong>Show unfiltered values</strong> option at the bottom of the <strong>Default values</strong> section.</li></ol></li></ol></li><li><p>Applicable to: Decide which widgets you want to apply this filter to. You can select the <strong>checkbox</strong> for <strong>All</strong>, or you can select individual widgets.</p></li><li><p>Link filters: Connect columns from different models that contain the same values (like campaign names, dates, or regions), so one filter can control data from all sources at once.</p></li><li><p>Filter options: Choose a display name for your filter, and decide whether you want to make it mandatory. To make a filter mandatory, select the <strong>checkbox</strong> that says <strong>Require users to select a filter value</strong>. If this is selected, users will not see widget visualizations on the dashboard until they select a filter value.</p></li></ol></li><li><p>When you are done configuring your filter, select the <strong>Apply</strong> button to apply your changes to your dashboard. You will then see your filter populate the list of filters at the top of the dashboard.</p></li></ol><h3 id="configure-dashboard-currency" tabindex="-1">Configure dashboard currency <a class="header-anchor" href="#configure-dashboard-currency" aria-label="Permalink to &quot;Configure dashboard currency&quot;">​</a></h3><p>To view your Branch data in your desired currency, you can set a currency filter at the dashboard level.</p><p>Important: Before you try to set a currency for your dashboard, make sure at least one of the widgets on your dashboard contains a currency-related measure.</p><p>To set the currency for your dashboard:</p><ol><li>Navigate to the dashboard you&#39;re interested in setting the currency for and select the <strong>three dot icon</strong> in the upper-right corner.</li><li>In the menu that opens, select <strong>Edit</strong>.</li><li>Select the <strong>Add parameter</strong> button in the top-right corner.</li><li>Select the parameter that says <strong>Currency</strong>.</li><li>A module will open, containing a list of all the possible currencies you can choose from. Search for a currency or scroll to select it from the list.</li><li>Select the <strong>Apply</strong> button.</li></ol><p>To remove the currency parameter from your dashboard, select the <strong>x icon</strong> on that parameter while you&#39;re in edit mode.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you&#39;d like to compare your data in multiple currencies, we recommend creating duplicate dashboards as necessary, and setting the desired currency on each.</p></div><h3 id="delete-a-dashboard" tabindex="-1">Delete a dashboard <a class="header-anchor" href="#delete-a-dashboard" aria-label="Permalink to &quot;Delete a dashboard&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Deleting a dashboard is a <strong>permanent</strong> action and cannot be undone.</p></div><p>Please note that dashboards where the author is listed as &quot;Branch&quot; cannot be deleted.</p><p>To delete a dashboard:</p><ol><li>Select <strong>Analysis</strong> in the left-side navigation in Branch, then select <strong>All Dashboards</strong>.</li><li>Find the dashboard you want to delete and select the <strong>checkbox</strong> near its name.</li><li>If you have the correct permissions to delete the dashboard, you will see the <strong>Delete</strong> button appear after selecting the checkbox.</li><li>Select the <strong>Delete</strong> button to permanently delete the dashboard.</li></ol><h2 id="widgets" tabindex="-1">Widgets <a class="header-anchor" href="#widgets" aria-label="Permalink to &quot;Widgets&quot;">​</a></h2><p>Widgets are what Analysis Dashboards are made of. Each widget contains a key metric or visualization. Widgets can also be used to store your notes.</p><p>Use widgets to display important data related to the general theme of your dashboard.</p><h3 id="create-and-configure-widget" tabindex="-1">Create and configure widget <a class="header-anchor" href="#create-and-configure-widget" aria-label="Permalink to &quot;Create and configure widget&quot;">​</a></h3><p>To create a new widget:</p><ol><li><p>Navigate to the dashboard you want to add the widget to and select the blue button at the bottom of the screen that says <strong>Add new widget</strong>.</p></li><li><p>In the top bar, use the dropdown to open the data sources menu. From the menu, select the data source you want your widget to draw from. If you want to use multiple sources, select <strong>Enable multiple sources</strong>.</p></li><li><p>Choose the columns (filters) you want to add to your widget. The categories are:</p><ol><li><p>Measures: These have a measurable, numeric value. Primarily related to quantities of user events and amount of revenue.</p></li><li><p>Attributes: Qualitative dimensions of your data, like <code>Campaign Name</code> or <code>Platform</code>.</p></li><li><p>Dates: Check the <strong>Date</strong> box to include a date column. To configure this column, select the <strong>filter</strong> <strong>icon</strong> next to it. Then decide if you want your widget to display rolling data (changes as time passes) or fixed data (static, covering a specific period of time).</p></li><li><p>Formulas: Add your own formulas to create your own custom calculations. Use either the free-form formula editor or the pre-built functions provided. Use the <strong>+ Add</strong> button to create new formulas. Select operators you&#39;re interested in from the list to learn more about how to use them.</p><ol><li>For example, use the formula <code>Ad Partner Name = &quot;Taptica&quot; and contains ( Campaign Name , &quot;spring&quot; )</code> to create a filter for Taptica campaigns you launched in the spring.</li></ol></li><li><p>Sets: There are two types of sets:</p><ol><li><p>Column set: A set based off a single column&#39;s data. Use the <strong>+ Add</strong> button to create new column sets.</p><ol><li>For example, select &quot;Branch Channel&quot; as the base column, then create a group for paid channels and a group for organic channels.</li></ol></li><li><p>Query set: A set based off a query that uses one or more columns of data. Use the <strong>+ Add</strong> button to create new query sets.</p><ol><li>For example, select &quot;OS&quot;, &quot;Feature&quot;, and &quot;Campaign Name&quot; for your base query, then create a group where <code>OS = Android</code>, <code>Feature = paid advertising</code>, and <code>Campaign Name = spring_solstice</code>.</li></ol></li></ol></li><li><p>Parameters: Create a custom name and specify whether the data&#39;s type should be integer, decimal, string, date, or boolean (true or false). Parameters let you decide which values you want to see included in your data, as well as what the default value should be. Use the <strong>+ Add</strong> button to create new parameters.</p></li></ol></li><li><p>For any columns you selected in step 3, you can add a filter to that column by selecting that column from the list. This way you can include or exclude the appropriate values for that column.</p></li><li><p>Select the <strong>Go</strong> button to run the data for your widget.</p></li><li><p>A suggested title for your widget will pre-populate for you, but you also have the option to change it to your own custom title.</p></li><li><p>Add a description to your widget to make it easier for others to quickly understand the data being displayed.</p></li><li><p>Your data will automatically be displayed in a suggested format, but you can also manually configure it as this point to be a table or a chart.</p><ol><li>If you choose the chart option, you will have the ability to select which type of chart you want your data displayed as by selecting the <strong>bar chart icon</strong> on the right side. Choose from a library of different types of charts, depending on your needs.</li></ol></li><li><p>Edit the chart, table, or metric&#39;s configuration by selecting the <strong>cog icon</strong> on the right side. There are two tabs:</p><ol><li>Configure: Determine which table columns to show/hide, or customize chart axes.</li><li>Settings: Additional display and formatting options, like text wrapping and table theme.</li></ol></li><li><p>Select the <strong>lowercase i icon</strong> on the right side to see exactly what the query that you&#39;ve built in this process looks like.</p></li><li><p>Once your query looks as expected and your visualization is properly formatted, select the <strong>Pin</strong> button to save your new widget. You will be able to choose which dashboard you want to save your widget to.</p></li></ol><h3 id="configure-widget-currency" tabindex="-1">Configure widget currency <a class="header-anchor" href="#configure-widget-currency" aria-label="Permalink to &quot;Configure widget currency&quot;">​</a></h3><p>It&#39;s possible <a href="./analysis-dashboards.html#configure-dashboard-currency">set the currency your data is reported in at the dashboard level</a>, but you can also do it at the widget level.</p><p>Important: If you have a currency set at the dashboard level, this will override any currency you set at the widget level.</p><p>To set the currency for a specific widget:</p><ol><li>Navigate to the dashboard containing the widget you&#39;re interested in. Make sure the widget has a currency-related measure.</li><li>Hover over the widget and select the <strong>three dot icon</strong> that appears.</li><li>Select <strong>Edit</strong>.</li><li>Find <strong>Currency</strong> under the <strong>Parameters</strong> section of the full list of columns you can add to your widget.</li><li>Click the <strong>pencil icon</strong> to modify the currency.</li><li>Search or scroll to find the currency you want to apply to your widget&#39;s data, then select it.</li><li>Select the <strong>Apply</strong> button.</li><li>Select the <strong>Save</strong> button.</li></ol><p>Please note that if your dashboard currently does not have a currency set, the first currency you set for a widget will be added as a parameter on the dashboard as well. Follow the instructions <a href="./analysis-dashboards.html#configure-dashboard-currency">here</a> if you&#39;d like to change it.</p><h3 id="view-widget-data" tabindex="-1">View widget data <a class="header-anchor" href="#view-widget-data" aria-label="Permalink to &quot;View widget data&quot;">​</a></h3><p>To view the underlying data that a widget is based on:</p><ol><li><p>Navigate to the dashboard containing the widget you&#39;re interested in.</p></li><li><p>Hover over the widget and select the <strong>three dot icon</strong> that appears.</p></li><li><p>Select <strong>Show underlying data</strong>.</p><ol><li>Please note that you cannot view underlying data for columns based on aggregate formulas.</li></ol></li><li><p>Select the <strong>Edit columns</strong> button to edit the columns displayed in this view.</p></li><li><p>Select <strong>Download CSV</strong> at the bottom-left of the module to download the data.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Editing which columns are displayed when viewing a widget&#39;s underlying data will also impact the columns included in the CSV download.</p></div><p>You can also explore widget data further without actually making changes to it:</p><ol><li><p>Navigate to the dashboard containing the widget you&#39;re interested in.</p></li><li><p>Hover over the widget and select the <strong>three dot icon</strong> that appears.</p></li><li><p>Select <strong>Explore</strong>.</p></li><li><p>From here, you can add filters, add columns, replace columns, or compare values.</p><ol><li>For example, you can quickly compare data where the &quot;Ad Partner Name&quot; is <code>amazon</code> versus <code>snap</code> to see which ad partner had more activity.</li></ol></li></ol><h3 id="edit-widget" tabindex="-1">Edit widget <a class="header-anchor" href="#edit-widget" aria-label="Permalink to &quot;Edit widget&quot;">​</a></h3><p>To edit the data displayed in a widget or how it is displayed:</p><ol><li>Navigate to the dashboard containing the widget you&#39;re interested in.</li><li>Hover over the widget and select the <strong>three dot icon</strong> that appears.</li><li>Select <strong>Edit</strong>. For more information on widget configuration, read &quot;<a href="./analysis-dashboards.html#create-and-configure-widget">Create and configure a widget</a>.&quot;</li><li>When you&#39;ve finished your edits, select the <strong>Save</strong> button. Then select the <strong>Close</strong> button at the top of the page.</li></ol><h3 id="display-widget-on-multiple-dashboards" tabindex="-1">Display widget on multiple dashboards <a class="header-anchor" href="#display-widget-on-multiple-dashboards" aria-label="Permalink to &quot;Display widget on multiple dashboards&quot;">​</a></h3><p>If you&#39;ve already created a widget and you want to copy it to a different dashboard:</p><ol><li>Navigate to the dashboard containing the widget you&#39;re interested in.</li><li>Hover over the widget and select the <strong>three dot icon</strong> that appears.</li><li>Select <strong>Pin</strong>.</li><li>Select the dashboard that you want to add your widget to, then select the <strong>Pin</strong> button.</li><li>When you visit the dashboard you selected, you will see that your widget has been added to it.</li></ol><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Editing a pinned widget in one dashboard will not impact that same widget in a different dashboard.</p></div><h3 id="delete-widget" tabindex="-1">Delete widget <a class="header-anchor" href="#delete-widget" aria-label="Permalink to &quot;Delete widget&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Deleting a widget is a <strong>permanent</strong> action and cannot be undone.</p></div><p>To delete a widget:</p><ol><li>Navigate to the dashboard containing the widget you want to delete.</li><li>Select the <strong>three dot icon</strong> in the upper-right corner of the dashboard.</li><li>Hover over the widget and select the <strong>three dot icon</strong> that appears.</li><li>Select <strong>Delete</strong> to permanently delete your widget.</li></ol><h3 id="display-custom-events" tabindex="-1">Display Custom Events <a class="header-anchor" href="#display-custom-events" aria-label="Permalink to &quot;Display Custom Events&quot;">​</a></h3><p>There&#39;s a wide variety of <a href="./track-branch-events.html#standard-events">Branch Standard Events</a> you can use to tell the story of your customer&#39;s journey. When you use the Branch SDK to track these events, they are automatically available for selection when creating and configuring a widget.</p><p>However, if necessary, you can also use a <a href="./track-branch-events.html#custom-events">Branch Custom Event</a> to describe your user&#39;s behavior. Unlike Standard Events, these are not automatically available to you when creating a widget. Instead, you&#39;ll need to use a Custom Event Template and specify which Custom Event you want to track.</p><p>To use a Custom Event Template:</p><ol><li><p>Navigate to the dashboard containing the widget you want to add a Custom Event to.</p></li><li><p>Either <a href="./analysis-dashboards.html#create-and-configure-widget">create</a> or start to <a href="./analysis-dashboards.html#edit-widget">edit</a> the relevant widget.</p></li><li><p>Make sure to select the correct <a href="./analysis-dashboards.html#key-terms">data source</a> (typically <strong>Activity</strong>).</p></li><li><p>In the columns section, expand <strong>Measures</strong>.</p></li><li><p>Find and select `<strong>Custom Event Template 0</strong>.</p></li><li><p>Select the <strong>Go</strong> button to run the query.</p><ol><li>Note: at this point, your widget will display a count of <code>0</code> because the template doesn&#39;t know which Custom Event to track yet.</li></ol></li><li><p>Find the <strong>filter bubble</strong> that says <code>custom_event_total_count_param_0 default</code> in the filter bar at the top of your widget configuration. Select this <strong>filter bubble</strong>.</p></li><li><p>In the dialogue that opens, enter your Custom Event name exactly as it appears in your Branch data (e.g., <code>First_registration</code> or <code>Level_completed</code> ).</p></li><li><p>Select the <strong>Apply</strong> button. The widget will now display the count for your specified Custom Event.</p></li><li><p>The filter will update to show <code>custom_event_total_count_param 0</code> followed by the name of your Custom Event.</p></li><li><p>Select the <strong>Pin</strong> button to save your widget to a dashboard.</p></li></ol><h4 id="use-multiple-custom-events" tabindex="-1">Use multiple Custom Events <a class="header-anchor" href="#use-multiple-custom-events" aria-label="Permalink to &quot;Use multiple Custom Events&quot;">​</a></h4><p>If you need to track multiple Custom Events in your dashboard, please note that:</p><ul><li>Each Custom Event requires its own template slot.</li><li>You can add additional Custom Event Templates beyond <code>Custom Event Template 0</code> (Template 1, Template 2, etc.) as separate measures.</li><li>Each template will have its own parameter to configure.</li><li>You can track up to five Custom Events (one per template slot).</li></ul><p><strong>Example</strong>: If tracking both <code>First_registration</code> and <code>Second_registration</code>, you would use <code>Custom Event Template 0</code> and set the parameter value to <code>First_registration</code> , then use <code>Custom Event Template 1</code> and set the parameter value to <code>Second_registration</code>.</p><div class="tip custom-block"><p class="custom-block-title">Tips</p><ul><li>Use the exact name of the Custom Event as it appears in your Branch data when setting the parameter in the template (case-sensitive)</li><li>The default parameter names (like <code>custom_event_total_count_param_0</code>) are technical but they&#39;ll become user-friendly like &quot;Custom Event First Registration&quot; after you set the value</li></ul></div><h3 id="set-kpi-alert" tabindex="-1">Set KPI alert <a class="header-anchor" href="#set-kpi-alert" aria-label="Permalink to &quot;Set KPI alert&quot;">​</a></h3><p>Set an alert on a widget to be notified when a certain criteria or threshold is met. If a particular widget can have an alert set on it, it will have a <strong>bell icon</strong> on it when you hover over it.</p><ol><li><p>Navigate to the dashboard containing the widget you want to set an alert on.</p></li><li><p>Hover over the widget and select the <strong>bell icon</strong> that appears.</p></li><li><p>Select an alert type from the pre-defined list of alerts. These include:</p><ol><li>&quot;KPI crosses a set limit&quot;</li><li>&quot;Regular KPI updates&quot;</li><li>&quot;Values of an attribute crosses a set limit&quot;</li><li>&quot;Regular updates on values of an attribute&quot;</li></ol></li><li><p>Select <strong>Next</strong>.</p></li><li><p>Give the alert a name and fill in the alert conditions with the appropriate values based on when you want the alert to fire.</p><ol><li>For example, set an alert to fire when your number of Open events goes over 25,000.</li><li>By default, values will be checked daily at 09:00 UTC. You can change this by selecting <strong>Change</strong> and selecting a new cadence and time of day.</li></ol></li><li><p>Add all the team members you want to receive this alert to the list of subscribers. You also have the option to add a custom message to be sent with the alert.</p></li><li><p>Confirm the structure of your alert by selecting <strong>View query</strong>.</p></li><li><p>When the alert looks how you expect, select the <strong>Create alert</strong> button.</p></li></ol><h3 id="manage-kpi-alert" tabindex="-1">Manage KPI alert <a class="header-anchor" href="#manage-kpi-alert" aria-label="Permalink to &quot;Manage KPI alert&quot;">​</a></h3><p>Alerts are managed at the widget level. To manage the alerts for a widget:</p><ol><li>Navigate to the dashboard containing the widget you&#39;re interested in.</li><li>Hover over the widget and select the three dot icon that appears.</li><li>Select <strong>Manage alerts</strong>.</li><li>Find the relevant alert, and select the <strong>three dot icon</strong> for it.</li><li>From this menu, you can select <strong>Edit alerts</strong>, <strong>Add subscribers</strong>, <strong>Unsubscribe from alerts</strong>, or <strong>Delete alerts</strong>.</li></ol><h2 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h2><p>AI is an important cornerstone of Analysis Dashboards. Your guide through this experience is Ivy, Branch&#39;s AI.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Please know that Ivy&#39;s answers are probabilistic, which means the same prompt may not always produce the exact same answer. Ivy&#39;s answers may contain errors and should be verified.</p><p>We recommend that you manually <a href="./analysis-dashboards.html#view-widget-data">confirm</a> that the models, filters, formulas, etc. your widgets are using are what you expect.</p></div><p>Ivy can answer your questions about data at both the dashboard and widget levels.</p><p>You can prompt Ivy from any dashboard or widget, with the exception of widgets used to store your text-based notes.</p><p>If Ivy can&#39;t process the entirety of your prompt, it will let you know and attempt to process part of it.</p><p>Once Ivy gives you an answer, you can change the visualization type (table, chart), pin it as a widget to a dashboard, download the answer&#39;s data, or <a href="./analysis-dashboards.html#edit-widget">edit the data</a>.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Selecting the <strong>Edit</strong> button on one of Ivy&#39;s answers also lets you see in more detail what models and columns it is using for the answer.</p></div><p>If Ivy gives you an answer that is a link, you can select that link to see more information about the columns it is using. In some cases, it may have created a new formula, set, etc. for you, which you will find in the left-side navigation along with the rest of the available columns. You will also see all the columns used listed at the top in the search bar.</p><p>If a blue line appears under a column name, you can select it to see alternatives suggested by Ivy.</p><p>At the end of every answer, you have the option to tell Ivy whether it interpreted your question correctly by selecting either the <strong>checkmark icon</strong> or <strong>X icon.</strong></p><p><strong>Dashboard level</strong></p><p>An individual dashboard is the highest level you can prompt Ivy from, but you can still ask Ivy questions about data that lives outside the dashboard you&#39;re asking questions from.</p><p>Prompting Ivy at the dashboard level is recommended when you want to create a truly unique widget. Otherwise, we recommend starting with a widget that is similar to what you&#39;re looking for, then prompting Ivy from there.</p><p><strong>Widget level</strong></p><p>When you prompt Ivy at the widget level, it will start by summarizing and re-iterating your question back to you. Use this output to confirm Ivy understood you correctly.</p><p>At this point it may also reference previous answers it has generated for you, to make sure it has built up the correct context between answers.</p><p>If Ivy makes changes to a previous answer, it will list these changes in shorthand form, for example <code>Added:Feature, Branch Channel = &#39;Short Links&#39;</code>. Make sure these changes are what you expect for your prompt.</p><h3 id="craft-prompts-for-ivy" tabindex="-1">Craft prompts for Ivy <a class="header-anchor" href="#craft-prompts-for-ivy" aria-label="Permalink to &quot;Craft prompts for Ivy&quot;">​</a></h3><p>Read the tips below and keep them in mind when crafting your own prompts for Ivy.</p><p><strong>Start broad, get narrow</strong></p><p>Instead of giving Ivy every detail upfront, ask a broader question first to establish a baseline, then build on the answers with more specific questions. Here is an example of a flow that uses this method:</p><p>Prompt 1: &quot;How many users completed trials this quarter?&quot;<br> Prompt 2: &quot;Break that down by OS.&quot;<br> Prompt 3: &quot;Now just show me users whose OS is Android.&quot;<br> Prompt 4: &quot;How many of these users are in Australia?&quot;</p><p><strong>Use context</strong></p><p>The more context Ivy has about your question, the better it will understand what you are asking it to do. This is the reason it can be easier to build new widgets by using widgets you already have, than by creating a widget from scratch.</p><p>If you already have a widget that is a good starting point for your question, select the <strong>Ivy</strong> button on that widget to prompt Ivy from within the context of that widget. It will use the original widget to inform its answer.</p><p><strong>Speak naturally, but be aware of keywords</strong></p><p>Ivy expects your prompts to be formatted in plain English, not using proper Branch column names. For example, you can ask Ivy &quot;What are the names of my top 5 campaigns?&quot; and not use <code>campaign_name</code> anywhere in the prompt.</p><p>However, there are certain phrases worth noting:</p><ul><li>&quot;Channel&quot; and &quot;Branch Channel&quot; are not the same column name. &quot;Branch Channel&quot; includes Journeys, Short Links, Paid Media, and SEO.</li><li>&quot;Paid advertising&quot; and &quot;non-paid advertising&quot; are useful ways to refer to owned and organic channels, respectively.</li><li>The term &quot;rate&quot; is generic based on the context, so try to make it more specific, like &quot;click-through percentage&quot;.</li></ul><p><strong>Specify time periods clearly</strong></p><p>Be specific about the time period you want Ivy to look at when gathering your data. Instead of using a word like &quot;recently&quot;, say &quot;in the past 7 days&quot;.</p><p><strong>Ask for comparisons</strong></p><p>Ivy excels at comparative analysis. You can ask it to compare sets of data across different time periods, channels, campaigns, and much more.</p><p><strong>Use numbers as filters</strong></p><p>Ivy also handles numeric filters well. You can use phrases like:</p><ul><li>&quot;Top 5&quot;</li><li>&quot;Above 10%&quot;</li><li>&quot;Higher than 80k&quot;</li></ul><h3 id="get-started-with-ivy" tabindex="-1">Get started with Ivy <a class="header-anchor" href="#get-started-with-ivy" aria-label="Permalink to &quot;Get started with Ivy&quot;">​</a></h3><p>Use these prompts as jumping off points to start conversations with Ivy:</p><ul><li>Which feature is driving most of my Short Link traffic?</li><li>Are there differences in audience demographics between Short Link and Journeys clickers?</li><li>Show me installs and opens for my top 5 paid advertising campaigns this quarter.</li><li>What are our email open rates by audience segment?</li><li>Show me click-through percentages for our top 10 email campaigns.</li><li>How many subscriptions did users start last quarter?</li><li>What&#39;s our paid advertising versus non-paid advertising install split this quarter?</li><li>How many purchase events came from each Branch channel this month?</li><li>How many registration forms were completed per campaign last quarter?</li><li>What&#39;s our install-to-purchase conversion rate by ad partner?</li><li>How many attributed installs do we have per geographic region for the past 60 days?</li><li>Compare iOS versus Android install performance by channel.</li><li>What day of the week has the highest engagement for clicks?</li><li>What proportion of deep link users performed an add to cart event?</li></ul><h2 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h2><p>Analysis Dashboards give you several ways to share your data and discoveries with your team.</p><h3 id="present-data" tabindex="-1">Present data <a class="header-anchor" href="#present-data" aria-label="Permalink to &quot;Present data&quot;">​</a></h3><p>To present a dashboard in presentation mode:</p><ol><li>Navigate to the dashboard you want to present.</li><li>Select the <strong>three dot icon</strong> in the upper-right corner of the dashboard, then select <strong>Present</strong>.</li><li>Use the arrows keys on your keypad or the arrow icons at the top of the presentation to move through the dashboard&#39;s widgets one by one.</li></ol><p>You can also enter presentation mode directly from a widget. To do this, hover over the widget and select the <strong>three dot icon</strong> that appears, then select <strong>Present</strong>.</p><h3 id="download-data" tabindex="-1">Download data <a class="header-anchor" href="#download-data" aria-label="Permalink to &quot;Download data&quot;">​</a></h3><p>To download an entire dashboard:</p><ol><li>Navigate to the dashboard you&#39;re interested in downloading.</li><li>Select the <strong>three dot icon</strong> in the upper-right corner of the dashboard, then select <strong>Download PDF</strong>.</li></ol><p>To download data from a single widget:</p><ol><li>Navigate to the widget you&#39;re interested in downloading.</li><li>Hover over the widget and select the <strong>three dot icon</strong> that appears, then select <strong>Download</strong>.</li><li>Choose your download type from the available options. The types of downloads available depend on the type of data in the widget.</li><li>Select the <strong>Download</strong> button.</li></ol><h3 id="share-dashboards" tabindex="-1">Share dashboards <a class="header-anchor" href="#share-dashboards" aria-label="Permalink to &quot;Share dashboards&quot;">​</a></h3><p>You can share one or more dashboards at a time with your teammates that have a Branch account:</p><ol><li>Navigate to the <a href="https://branchdocs.app.link/e/dashboards-overview-to-all-dashboards" target="_blank" rel="noreferrer"><strong>All Dashboards</strong></a>page under <strong>Analysis</strong> in the left-side navigation of Branch.</li><li>Select the checkbox next to the dashboard(s) you want to share. Select the <strong>Share</strong> button.</li><li>Add either entire groups or individual users to the list of entities to share the dashboard(s) with. Decide whether each entity can view or edit the dashboard(s) you&#39;re sharing.</li><li>Select the <strong>Share</strong> button. These users will receive an email and see your dashboard appear in their list of <strong>All Dashboards</strong>.</li></ol><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h2><p>Branch University offers <strong>live</strong>, <strong>expert-led trainings</strong> covering the new Branch experience, including Analysis. Learn more <a href="https://branchdocs.app.link/e/dashboards-live-training" target="_blank" rel="noreferrer">here</a>.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>What is a dashboard?</summary><p>Dashboards are individual pages that bring together a collection of metrics/charts (widgets) in one place, where you can compare them side by side.</p></details><details><summary>What is a widget?</summary><p>Widgets are individual metrics or charts that display aspects of your Branch data. They can be edited and customized to capture the data you need. Ivy&#39;s responses can be turned into new widgets that get pinned to dashboards.</p></details><details><summary>Can I create and edit Analysis Dashboard?</summary><p>Yes, but the ability to create or edit Analysis Dashboards depends on your Branch package. Some packages only allow viewing <a href="./branch-analysis.html#default-dashboards">default dashboards</a>.</p></details><details><summary>What is Ivy?</summary><p>Ivy is Brach&#39;s integrated AI. It helps you uncover insights and answers your business questions in real time.</p></details><details><summary>Can I download data from Analysis Dashboards?</summary><p>Yes, you can download entire dashboards or data from individual widgets in various formats.</p></details><details><summary>What types of filters can I apply to my dashboards?</summary><p>You can apply filters to include or exclude specific data, and you can configure them to apply to all or individual widgets.</p></details><details><summary>What should I do if I see the error &quot;Some x-axis values cannot be sliced by color because they have multiple y-axis values&quot;?</summary><p>Try to switch from chart view to table view for your data.</p></details><details><summary>What does &quot;Viewing underlying data is not supported when there are chasm traps, fan traps, or for columns based on aggregate formulas&quot; mean?</summary><p>This likely means that you are trying to view underlying data for a widget where the metric is calculated based off aggregate values that cannot be displayed more granularly because of the columns selected for the widget.</p></details><details><summary>What does &quot;Total Count&quot; refer to?</summary><p>&quot;Total Count&quot; includes impressions, clicks, opens, and installs.</p></details><details><summary>What if Ivy&#39;s answer doesn&#39;t look the way I expect it to? How can I know exactly what data Ivy is pulling from?</summary><p>Select the <strong>Edit</strong> button to be taken to the configuration page where all available columns are displayed, as well as the columns used in the answer. From here you can view the answer in more detail and edit it.</p></details>',170)])])}const g=t(i,[["render",s]]);export{p as __pageData,g as default};
